kernel_src="""

#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelLogSoftmaxCustom {
public:
    __aicore__ inline KernelLogSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                int32_t dim, uint32_t rowLength)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        dim_ = dim;
        rowLen_ = rowLength;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, rowLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, rowLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, rowLen_ * sizeof(float));
        pipe_.InitBuffer(scalarBuf_, 1, sizeof(float));  // for max and sum scalars
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0 || rowLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        const uint32_t totalRows = totalLen_ / rowLen_;
        const uint32_t tileRows = tileLen_ / rowLen_;  // tileLen_ is rowLen_ (1 row per tile)
        const uint32_t rowStride = blockNum * tileRows;

        uint32_t curRow = blockIdx * tileRows;
        if (curRow >= totalRows) return;

        // Process rows within this block's tile
        for (uint32_t i = 0; i < tileRows; ++i) {
            uint32_t row = curRow + i;
            if (row >= totalRows) break;
            uint32_t gmOffset = row * rowLen_;

            CopyIn(gmOffset);
            Compute(gmOffset);
            CopyOut(gmOffset);
        }
    }

private:
    __aicore__ inline void CopyIn(uint32_t gmOffset)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[gmOffset], rowLen_);
        inQueueX_.EnQue(xLocal);
    }

    __aicore__ inline void Compute(uint32_t gmOffset)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
        AscendC::LocalTensor<float> tLocal = tmpQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> maxScalar = scalarBuf_.Get<float>();  // reuse same buffer
        AscendC::LocalTensor<float> sumScalar = scalarBuf_.Get<float>(); // same buffer, will be overwritten

        // tLocal = xLocal (copy)
        AscendC::DataCopy(tLocal, xLocal, rowLen_);

        // maxVal = max(tLocal)
        AscendC::ReduceMax(maxScalar, tLocal, rowLen_, AscendC::ReductionParams());
        float maxVal = AscendC::GetScalar<float>(maxScalar);

        // xLocal = xLocal - maxVal  (vector scalar subtraction)
        AscendC::Sub(xLocal, xLocal, maxVal, rowLen_);

        // tLocal = exp(xLocal)
        AscendC::Exp(tLocal, xLocal, rowLen_);

        // sumVal = sum(tLocal)
        AscendC::ReduceSum(sumScalar, tLocal, rowLen_, AscendC::ReductionParams());
        float sumVal = AscendC::GetScalar<float>(sumScalar);

        // logSum = log(sumVal)
        // Copy sumVal into a scalar tensor and apply Log
        AscendC::DataCopy(maxScalar, sumScalar, 1); // reuse maxScalar as log input
        AscendC::Log(sumScalar, maxScalar, 1);       // log(out, in, len)
        float logSum = AscendC::GetScalar<float>(sumScalar);

        // yLocal = xLocal - (maxVal + logSum)
        float addVal = maxVal + logSum;
        AscendC::Sub(yLocal, xLocal, addVal, rowLen_);

        tmpQueue_.FreeTensor(tLocal);
        outQueueY_.EnQue<float>(yLocal);
        inQueueX_.FreeTensor(xLocal);
    }

    __aicore__ inline void CopyOut(uint32_t gmOffset)
    {
        AscendC::LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
        AscendC::DataCopy(yGm_[gmOffset], yLocal, rowLen_);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> scalarBuf_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    int32_t dim_ {1};
    uint32_t rowLen_ {0};
};

extern "C" __global__ __aicore__ void log_softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelLogSoftmaxCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength, tiling_data.dim, tiling_data.rowLength);
    op.Process();
}
